MP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(CASE WHEN fhirpath_text(PalliativeDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(PalliativeDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PalliativeDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PalliativeDiagnosis.resource, 'recordedDate')), fhirpath_text(PalliativeDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(PalliativeDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PalliativeDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PalliativeDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(PalliativeDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(PalliativeDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PalliativeDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PalliativeDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(PalliativeDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PalliativeDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PalliativeDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) >= CAST(LEFT(REPLACE(CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR)) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Encounter: Palliative Care Encounter" WHERE fhirpath_text(resource, 'status') IN ('finished')) AS PalliativeEncounter WHERE PalliativeEncounter.patient_id = p.patient_id AND CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(PalliativeEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(PalliativeEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) >= CAST(LEFT(REPLACE(CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR)) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Procedure: Palliative Care Intervention" WHERE fhirpath_text(resource, 'status') IN ('completed')) AS PalliativeIntervention WHERE PalliativeIntervention.patient_id = p.patient_id AND CAST(LEFT(REPLACE(CAST(intervalStart(CASE WHEN fhirpath_text(PalliativeIntervention.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(PalliativeIntervention.resource, 'performed')), '{') THEN fhirpath_text(PalliativeIntervention.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(PalliativeIntervention.resource, 'performed'), fhirpath_text(PalliativeIntervention.resource, 'performed'), TRUE, TRUE) END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(CASE WHEN fhirpath_text(PalliativeIntervention.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(PalliativeIntervention.resource, 'performed')), '{') THEN fhirpath_text(PalliativeIntervention.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(PalliativeIntervention.resource, 'performed'), fhirpath_text(PalliativeIntervention.resource, 'performed'), TRUE, TRUE) END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) >= CAST(LEFT(REPLACE(CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR))
),
"SDE.SDE Ethnicity" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-ethnicity'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_E -> json_object('codes', "Distinct"(list_concat([fhirpath_text(_lt_E, 'ombCategory')], fhirpath_text(_lt_E, 'detailed'))), 'display', fhirpath_text(_lt_E, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Payer" AS (
SELECT _inner.patient_id, _inner._resource_data AS resource FROM (SELECT patient_id, json_object('code', Payer.type, 'period', fhirpath_text(Payer.resource, 'period')) AS _resource_data FROM "Coverage: Payer Type" AS Payer) AS _inner
),
"SDE.SDE Race" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-race'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_R -> json_object('codes', CASE WHEN fhirpath_text(_lt_R, 'ombCategory') IS NOT NULL  AND fhirpath_text(_lt_R, 'detailed') IS NOT NULL  THEN "Distinct"(jsonConcat(fhirpath_text(_lt_R, 'ombCategory'), fhirpath_text(_lt_R, 'detailed'))) ELSE NULL END, 'display', fhirpath_text(_lt_R, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Sex" AS (
SELECT p.patient_id, (SELECT CASE WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248153007' THEN 'http://snomed.info/sct|248153007' WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248152002' THEN 'http://snomed.info/sct|248152002' ELSE NULL END) AS value FROM _patients AS p
),
"AIFrailLTCF.Is Age 66 or Older with Advanced Illness and Frailty" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) - EXTRACT(YEAR FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) - CASE WHEN EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) OR EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) = EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) AND EXTRACT(DAY FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(DAY FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) THEN 1 ELSE 0 END >= 66 AND EXISTS (SELECT 1 FROM "AIFrailLTCF.Has Criteria Indicating Frailty" AS sub WHERE sub.patient_id = p.patient_id) AND (EXISTS (SELECT 1 FROM "AIFrailLTCF.Has Advanced Illness in Year Before or During Measurement Period" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "AIFrailLTCF.Has Dementia Medications in Year Before or During Measurement Period" AS sub WHERE sub.patient_id = p.patient_id))
),
"AIFrailLTCF.Is Age 66 to 80 with Advanced Illness and Frailty or Is Age 81 or Older with Frailty" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) - EXTRACT(YEAR FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) - CASE WHEN EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) OR EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) = EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) AND EXTRACT(DAY FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(DAY FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) THEN 1 ELSE 0 END BETWEEN 66 AND 80 AND EXISTS (SELECT 1 FROM "AIFrailLTCF.Has Criteria Indicating Frailty" AS sub WHERE sub.patient_id = p.patient_id) AND (EXISTS (SELECT 1 FROM "AIFrailLTCF.Has Advanced Illness in Year Before or During Measurement Period" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "AIFrailLTCF.Has Dementia Medications in Year Before or During Measurement Period" AS sub WHERE sub.patient_id = p.patient_id)) OR EXTRACT(YEAR FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) - EXTRACT(YEAR FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) - CASE WHEN EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) OR EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) = EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) AND EXTRACT(DAY FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(DAY FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) THEN 1 ELSE 0 END >= 81 AND EXISTS (SELECT 1 FROM "AIFrailLTCF.Has Criteria Indicating Frailty" AS sub WHERE sub.patient_id = p.patient_id)
),
"End Stage Renal Disease Encounter" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Encounter: ESRD Monthly Outpatient Services" WHERE fhirpath_text(resource, 'status') IN ('finished')) AS ESRDEncounter WHERE LEFT(CAST(intervalStart(fhirpath_text(ESRDEncounter.resource, 'period')) AS VARCHAR), 10) <= LEFT(CAST(CAST('2026-12-31T23:59:59.999' AS VARCHAR) AS VARCHAR), 10)
),
"End Stage Renal Disease Procedures" AS (
SELECT * FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Procedure: Kidney Transplant" UNION SELECT patient_id, resource FROM "Procedure: Dialysis Services") AS _union WHERE fhirpath_text(resource, 'status') IN ('completed')) AS ESRDProcedure WHERE LEFT(CAST(intervalEnd(CASE WHEN fhirpath_text(ESRDProcedure.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(ESRDProcedure.resource, 'performed')), '{') THEN fhirpath_text(ESRDProcedure.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(ESRDProcedure.resource, 'performed'), fhirpath_text(ESRDProcedure.resource, 'performed'), TRUE, TRUE) END) AS VARCHAR), 10) <= LEFT(CAST(CAST('2026-12-31T23:59:59.999' AS VARCHAR) AS VARCHAR), 10)
),
"Essential Hypertension Diagnosis" AS (
SELECT * FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Condition: Essential Hypertension (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Essential Hypertension (qicore-condition-encounter-diagnosis)") AS _union WHERE fhirpath_text(resource, 'verificationStatus') IS NULL OR fhirpath_text(resource, 'verificationStatus') IN ('confirmed', 'unconfirmed', 'provisional', 'differential')) AS Hypertension WHERE intervalOverlaps(CASE WHEN fhirpath_text(Hypertension.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(Hypertension.resource, 'onsetDateTime'), fhirpath_text(Hypertension.resource, 'onsetPeriod.start'), fhirpath_text(Hypertension.resource, 'recordedDate')), fhirpath_text(Hypertension.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(Hypertension.resource, 'onsetDateTime'), fhirpath_text(Hypertension.resource, 'onsetPeriod.start'), fhirpath_text(Hypertension.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(Hypertension.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(Hypertension.resource, 'onsetDateTime'), fhirpath_text(Hypertension.resource, 'onsetPeriod.start'), fhirpath_text(Hypertension.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(Hypertension.resource, 'onsetDateTime'), fhirpath_text(Hypertension.resource, 'onsetPeriod.start'), fhirpath_text(Hypertension.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END, intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(dateAddQuantity(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), '{"value": 6.0, "unit": "month", "system": "http://unitsofmeasure.org"}') AS VARCHAR), TRUE, FALSE))
),
"Initial Population" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) - EXTRACT(YEAR FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) - CASE WHEN EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) OR EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) = EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) AND EXTRACT(DAY FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(DAY FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) THEN 1 ELSE 0 END BETWEEN 18 AND 85 AND EXISTS (SELECT 1 FROM "Essential Hypertension Diagnosis" AS sub WHERE sub.patient_id = p.patient_id) AND EXISTS (SELECT 1 FROM "AdultOutpatientEncounters.Qualifying Encounters" AS sub WHERE sub.patient_id = p.patient_id)
),
"Denominator" AS (
SELECT * FROM "Initial Population"
),
"Pregnancy or Renal Diagnosis" AS (
SELECT * FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Condition: Pregnancy (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Pregnancy (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: End Stage Renal Disease (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: End Stage Renal Disease (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Kidney Transplant Recipient (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Kidney Transplant Recipient (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Chronic Kidney Disease, Stage 5 (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Chronic Kidney Disease, Stage 5 (qicore-condition-encounter-diagnosis)") AS _union WHERE fhirpath_text(resource, 'verificationStatus') IS NULL OR fhirpath_text(resource, 'verificationStatus') IN ('confirmed', 'unconfirmed', 'provisional', 'differential')) AS PregnancyESRDDiagnosis WHERE intervalOverlaps(CASE WHEN fhirpath_text(PregnancyESRDDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(PregnancyESRDDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PregnancyESRDDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PregnancyESRDDiagnosis.resource, 'recordedDate')), fhirpath_text(PregnancyESRDDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(PregnancyESRDDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PregnancyESRDDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PregnancyESRDDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(PregnancyESRDDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(PregnancyESRDDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PregnancyESRDDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PregnancyESRDDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(PregnancyESRDDiagnosis.resource, 'onsetDateTime'), fhirpath_text(PregnancyESRDDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(PregnancyESRDDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END, intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE))
),
"Denominator Exclusions" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Hospice.Has Hospice Services" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Pregnancy or Renal Diagnosis" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "End Stage Renal Disease Procedures" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "End Stage Renal Disease Encounter" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "AIFrailLTCF.Is Age 66 to 80 with Advanced Illness and Frailty or Is Age 81 or Older with Frailty" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "AIFrailLTCF.Is Age 66 or Older Living Long Term in a Nursing Home" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "PalliativeCare.Has Palliative Care in the Measurement Period" AS sub WHERE sub.patient_id = p.patient_id)
),
"Qualifying Diastolic Blood Pressure Reading" AS (
(SELECT * FROM (SELECT patient_id, resource FROM "Observation (us-core-blood-pressure)" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS BloodPressure WHERE NOT EXISTS (SELECT 1 FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Encounter: Encounter Inpatient" UNION SELECT patient_id, resource FROM "Encounter: Emergency Department Evaluation and Management Visit") AS _union WHERE fhirpath_text(resource, 'status') IN ('finished')) AS DisqualifyingEncounter WHERE CAST(LEFT(REPLACE(CAST(COALESCE(CAST(fhirpath_date(BloodPressure.resource, 'effectiveDateTime') AS VARCHAR), intervalEnd(fhirpath_text(BloodPressure.resource, 'effectivePeriod'))) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) >= CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(DisqualifyingEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND CAST(LEFT(REPLACE(CAST(COALESCE(CAST(fhirpath_date(BloodPressure.resource, 'effectiveDateTime') AS VARCHAR), intervalEnd(fhirpath_text(BloodPressure.resource, 'effectivePeriod'))) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(DisqualifyingEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND DisqualifyingEncounter.patient_id = BloodPressure.patient_id)) UNION (SELECT * FROM (SELECT patient_id, resource FROM "Observation (us-core-blood-pressure)" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS BloodPressure WHERE NOT array_contains(['EMER', 'IMP', 'ACUTE', 'NONAC', 'PRENC', 'SS'], fhirpath_text(CASE WHEN (SELECT COUNT(*) FROM "Encounter" AS E WHERE fhirpath_text(E.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(BloodPressure.resource, 'encounter.reference'), '/'), -1) AND E.patient_id = BloodPressure.patient_id) = 1 THEN (SELECT resource FROM "Encounter" AS E WHERE fhirpath_text(E.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(BloodPressure.resource, 'encounter.reference'), '/'), -1) AND E.patient_id = BloodPressure.patient_id LIMIT 1) ELSE NULL END, 'class.code')) AND CAST(LEFT(REPLACE(CAST(COALESCE(CAST(fhirpath_date(BloodPressure.resource, 'effectiveDateTime') AS VARCHAR), intervalEnd(fhirpath_text(BloodPressure.resource, 'effectivePeriod'))) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) >= CAST(LEFT(REPLACE(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND CAST(LEFT(REPLACE(CAST(COALESCE(CAST(fhirpath_date(BloodPressure.resource, 'effectiveDateTime') AS VARCHAR), intervalEnd(fhirpath_text(BloodPressure.resource, 'effectivePeriod'))) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR))
),
"Qualifying Systolic Blood Pressure Reading" AS (
(SELECT * FROM (SELECT patient_id, resource FROM "Observation (us-core-blood-pressure)" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS BloodPressure WHERE NOT EXISTS (SELECT 1 FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Encounter: Encounter Inpatient" UNION SELECT patient_id, resource FROM "Encounter: Emergency Department Evaluation and Management Visit") AS _union WHERE fhirpath_text(resource, 'status') IN ('finished')) AS DisqualifyingEncounter WHERE CAST(LEFT(REPLACE(CAST(COALESCE(CAST(fhirpath_date(BloodPressure.resource, 'effectiveDateTime') AS VARCHAR), intervalEnd(fhirpath_text(BloodPressure.resource, 'effectivePeriod'))) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) >= CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(DisqualifyingEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND CAST(LEFT(REPLACE(CAST(COALESCE(CAST(fhirpath_date(BloodPressure.resource, 'effectiveDateTime') AS VARCHAR), intervalEnd(fhirpath_text(BloodPressure.resource, 'effectivePeriod'))) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(DisqualifyingEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND DisqualifyingEncounter.patient_id = BloodPressure.patient_id)) UNION (SELECT * FROM (SELECT patient_id, resource FROM "Observation (us-core-blood-pressure)" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS BloodPressure WHERE NOT array_contains(['EMER', 'IMP', 'ACUTE', 'NONAC', 'PRENC', 'SS'], fhirpath_text(CASE WHEN (SELECT COUNT(*) FROM "Encounter" AS E WHERE fhirpath_text(E.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(BloodPressure.resource, 'encounter.reference'), '/'), -1) AND E.patient_id = BloodPressure.patient_id) = 1 THEN (SELECT resource FROM "Encounter" AS E WHERE fhirpath_text(E.resource, 'id') = LIST_EXTRACT(STR_SPLIT(fhirpath_text(BloodPressure.resource, 'encounter.reference'), '/'), -1) AND E.patient_id = BloodPressure.patient_id LIMIT 1) ELSE NULL END, 'class.code')) AND CAST(LEFT(REPLACE(CAST(COALESCE(CAST(fhirpath_date(BloodPressure.resource, 'effectiveDateTime') AS VARCHAR), intervalEnd(fhirpath_text(BloodPressure.resource, 'effectivePeriod'))) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) >= CAST(LEFT(REPLACE(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND CAST(LEFT(REPLACE(CAST(COALESCE(CAST(fhirpath_date(BloodPressure.resource, 'effectiveDateTime') AS VARCHAR), intervalEnd(fhirpath_text(BloodPressure.resource, 'effectivePeriod'))) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR))
),
"Blood Pressure Days" AS (
(SELECT DBPExam.patient_id, LEFT(REPLACE(CAST(COALESCE(CAST(fhirpath_date(DBPExam.resource, 'effectiveDateTime') AS VARCHAR), intervalEnd(fhirpath_text(DBPExam.resource, 'effectivePeriod'))) AS VARCHAR), ' ', 'T'), 10) AS value FROM "Qualifying Diastolic Blood Pressure Reading" AS DBPExam) INTERSECT (SELECT SBPExam.patient_id, LEFT(REPLACE(CAST(COALESCE(CAST(fhirpath_date(SBPExam.resource, 'effectiveDateTime') AS VARCHAR), intervalEnd(fhirpath_text(SBPExam.resource, 'effectivePeriod'))) AS VARCHAR), ' ', 'T'), 10) AS value FROM "Qualifying Systolic Blood Pressure Reading" AS SBPExam)
),
"Most Recent Blood Pressure Day" AS (
SELECT p.patient_id, (SELECT value FROM "Blood Pressure Days" AS BPDays WHERE BPDays.patient_id = p.patient_id ORDER BY value ASC NULLS LAST LIMIT 1) AS value FROM _patients AS p
),
"Lowest Diastolic Reading on Most Recent Blood Pressure Day" AS (
SELECT p.patient_id, (SELECT fhirpath_number(DBPReading.resource, 'component.where(code.coding.display = ''Diastolic blood pressure'').valueQuantity.value') FROM "Qualifying Diastolic Blood Pressure Reading" AS DBPReading WHERE cqlSameAsP(CAST(COALESCE(CAST(fhirpath_date(DBPReading.resource, 'effectiveDateTime') AS VARCHAR), intervalEnd(fhirpath_text(DBPReading.resource, 'effectivePeriod'))) AS VARCHAR), CAST((SELECT sub.value FROM "Most Recent Blood Pressure Day" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) AS VARCHAR), 'day') AND DBPReading.patient_id = p.patient_id ORDER BY fhirpath_number(DBPReading.resource, 'component.where(code.coding.display = ''Diastolic blood pressure'').valueQuantity.value') ASC NULLS LAST, json_extract_string(DBPReading.resource, '$.id') ASC NULLS LAST LIMIT 1) AS value FROM _patients AS p
),
"Has Diastolic Blood Pressure Less Than 90" AS (
SELECT p.patient_id FROM _patients AS p WHERE (SELECT sub.value FROM "Lowest Diastolic Reading on Most Recent Blood Pressure Day" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) < 90.0
),
"Lowest Systolic Reading on Most Recent Blood Pressure Day" AS (
SELECT p.patient_id, (SELECT fhirpath_number(SBPReading.resource, 'component.where(code.coding.display = ''Systolic blood pressure'').valueQuantity.value') FROM "Qualifying Systolic Blood Pressure Reading" AS SBPReading WHERE cqlSameAsP(CAST(COALESCE(CAST(fhirpath_date(SBPReading.resource, 'effectiveDateTime') AS VARCHAR), intervalEnd(fhirpath_text(SBPReading.resource, 'effectivePeriod'))) AS VARCHAR), CAST((SELECT sub.value FROM "Most Recent Blood Pressure Day" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) AS VARCHAR), 'day') AND SBPReading.patient_id = p.patient_id ORDER BY fhirpath_number(SBPReading.resource, 'component.where(code.coding.display = ''Systolic blood pressure'').valueQuantity.value') ASC NULLS LAST, json_extract_string(SBPReading.resource, '$.id') ASC NULLS LAST LIMIT 1) AS value FROM _patients AS p
),
"Has Systolic Blood Pressure Less Than 140" AS (
SELECT p.patient_id FROM _patients AS p WHERE (SELECT sub.value FROM "Lowest Systolic Reading on Most Recent Blood Pressure Day" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) < 140.0
),
"Numerator" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Has Systolic Blood Pressure Less Than 140" AS sub WHERE sub.patient_id = p.patient_id) AND EXISTS (SELECT 1 FROM "Has Diastolic Blood Pressure Less Than 90" AS sub WHERE sub.patient_id = p.patient_id)
),
"SDE Ethnicity" AS (
SELECT * FROM "SDE.SDE Ethnicity"
),
"SDE Payer" AS (
SELECT * FROM "SDE.SDE Payer"
),
"SDE Race" AS (
SELECT * FROM "SDE.SDE Race"
),
"SDE Sex" AS (
SELECT * FROM "SDE.SDE Sex"
)
SELECT p.patient_id, (SELECT CASE WHEN "Initial Population".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Initial Population", (SELECT CASE WHEN "Denominator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Denominator, (SELECT CASE WHEN "Denominator Exclusions".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Denominator Exclusions", (SELECT CASE WHEN "Numerator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Numerator FROM _patients p LEFT JOIN "Initial Population" ON p.patient_id = "Initial Population".patient_id LEFT JOIN "Denominator" ON p.patient_id = "Denominator".patient_id LEFT JOIN "Denominator Exclusions" ON p.patient_id = "Denominator Exclusions".patient_id LEFT JOIN "Numerator" ON p.patient_id = "Numerator".patient_id ORDER BY p.patient_id ASC
